```cpp
/**
 * @brief Binary Search Implementation using Recursion
 * 
 * This function recursively divides the array into two halves and checks if the current value is in between them. The time complexity of this function is O(log n) since it only requires a linear time division.
 * 
 * @param arr - The initial array to be divided recursively
 * @param l - Starting index of the first half of the array
 * @param r - Ending index of the first half of the array
 * @param value - The value to be searched for
 * @return True if the value is present in the first half, false otherwise
 */
bool binarySearch(int arr[], int l, int r, int val) {
    if (l >= r) {
        return false; // Base case: both halves are empty or contain only one element.
    }

    int mid = (l + r) / 2;

    if (arr[mid] == val) {
        return true; // Found the value in the first half!
    } else if (arr[mid] < val) {
        return binarySearch(arr, l, mid - 1, val); // Recursively search for smaller values to the left of current value
    } else {
        return binarySearch(arr, mid + 1, r, val); // Recursively search for larger values to the right of current value
    }
}
```

